proof_block:
// Strategy shift from attempt 1: rather than propositional
// `assert(hyp_i ==> X)` skeletons (which don't add real facts to z3's
// context), case-split on `pre_self_@.received_packet` and on
// `cpacket.msg`'s variant so each branch of `receive_packet`'s
// disjunction lands in a context where z3 can directly equate the
// per-run post-states and per-run outputs.
let (sp1, ack1) = r1;
let (sp2, ack2) = r2;
let pre_v   = pre_self_@;
let pkt_v   = cpacket@;

// Pull every conjunct of `host_state_common_postconditions` for both
// runs.  `host_state_common_postconditions` is already revealed by the
// scaffolding, so each `assert ... by` succeeds by unfolding the spec.
assert(post1_self_.host_state_common_postconditions(pre_self_, cpacket, sp1@) ==> {
    &&& post1_self_.abstractable()
    &&& post1_self_.constants == pre_self_.constants
    &&& cpacket_seq_is_abstractable(sp1@)
    &&& post1_self_.next_action_index == pre_self_.next_action_index
    &&& outbound_packet_seq_is_valid(sp1@)
    &&& outbound_packet_seq_has_correct_srcs(sp1@, pre_self_.constants.me@)
});
assert(post2_self_.host_state_common_postconditions(pre_self_, cpacket, sp2@) ==> {
    &&& post2_self_.abstractable()
    &&& post2_self_.constants == pre_self_.constants
    &&& cpacket_seq_is_abstractable(sp2@)
    &&& post2_self_.next_action_index == pre_self_.next_action_index
    &&& outbound_packet_seq_is_valid(sp2@)
    &&& outbound_packet_seq_has_correct_srcs(sp2@, pre_self_.constants.me@)
});

// Sequence/set-extensionality on the LSHT round-trip identity from
// `host_state_common_postconditions` -- materialise the `to_set()` skeleton
// of `abstractify_seq_of_cpackets_to_set_of_sht_packets` on both runs.
assert(post1_self_.host_state_common_postconditions(pre_self_, cpacket, sp1@) ==>
    abstractify_seq_of_cpackets_to_set_of_sht_packets(sp1@) =~=
    extract_packets_from_lsht_packets(
        abstractify_outbound_packets_to_seq_of_lsht_packets(sp1@)));
assert(post2_self_.host_state_common_postconditions(pre_self_, cpacket, sp2@) ==>
    abstractify_seq_of_cpackets_to_set_of_sht_packets(sp2@) =~=
    extract_packets_from_lsht_packets(
        abstractify_outbound_packets_to_seq_of_lsht_packets(sp2@)));

// Each run's `receive_packet` is the disjunction `A_i ||| B_i`.  Materialise
// the case-split on the shared scrutinee `pre_v.received_packet`:
//   * `pre_v.received_packet is None`  : case B's first conjunct
//     (`pre.received_packet is Some || okay_to_ignore_packets()`) is only
//     true via the opaque `okay_to_ignore_packets()` branch, which z3
//     can't see without `reveal(okay_to_ignore_packets)`.  We don't reveal
//     it, so case A is the only branch that z3 can constructively pick;
//     both runs end up in case A and inherit `SingleDelivery::receive` on
//     the shared `(pre_v.sd, pkt_v)`.
//   * `pre_v.received_packet is Some`  : case A's first conjunct
//     (`pre.received_packet is None`) is false; both runs collapse into
//     case B with `post == pre` and `out == empty`.  That forces
//     `post1_self_@ == pre_v == post2_self_@` and
//     `abstractify_seq_of_cpackets_to_set_of_sht_packets(sp_i@) == empty`,
//     which by set-extensionality forces both `sp_i@` to be the empty Seq.
if pre_v.received_packet is Some {
    // Case B forced for both runs.
    assert(receive_packet(pre_v, post1_self_@, pkt_v,
            abstractify_seq_of_cpackets_to_set_of_sht_packets(sp1@), ack1@@)
        ==> post1_self_@ == pre_v
            && abstractify_seq_of_cpackets_to_set_of_sht_packets(sp1@) == Set::<Packet>::empty());
    assert(receive_packet(pre_v, post2_self_@, pkt_v,
            abstractify_seq_of_cpackets_to_set_of_sht_packets(sp2@), ack2@@)
        ==> post2_self_@ == pre_v
            && abstractify_seq_of_cpackets_to_set_of_sht_packets(sp2@) == Set::<Packet>::empty());

    // Cross-run equality on the abstract host state.
    assert(receive_packet(pre_v, post1_self_@, pkt_v,
                abstractify_seq_of_cpackets_to_set_of_sht_packets(sp1@), ack1@@)
        && receive_packet(pre_v, post2_self_@, pkt_v,
                abstractify_seq_of_cpackets_to_set_of_sht_packets(sp2@), ack2@@)
        ==> post1_self_@ == post2_self_@);
} else {
    // pre_v.received_packet is None.  Without revealing okay_to_ignore_packets,
    // z3 sees `pre.received_packet is Some` as false and the opaque
    // disjunct is unknown -- so case B is unprovable here.  Case A is the
    // only branch.  Materialise the SingleDelivery::receive relation and
    // the post-state struct-update equality on the shared (pre_v, pkt_v).
    assert(receive_packet(pre_v, post1_self_@, pkt_v,
            abstractify_seq_of_cpackets_to_set_of_sht_packets(sp1@), ack1@@)
        && pre_v.received_packet is None
        ==>
            SingleDelivery::receive(pre_v.sd, post1_self_@.sd, pkt_v, ack1@@,
                abstractify_seq_of_cpackets_to_set_of_sht_packets(sp1@))
            && post1_self_@ == AbstractHostState {
                sd: post1_self_@.sd,
                received_packet: post1_self_@.received_packet,
                ..post1_self_@
            });
    assert(receive_packet(pre_v, post2_self_@, pkt_v,
            abstractify_seq_of_cpackets_to_set_of_sht_packets(sp2@), ack2@@)
        && pre_v.received_packet is None
        ==>
            SingleDelivery::receive(pre_v.sd, post2_self_@.sd, pkt_v, ack2@@,
                abstractify_seq_of_cpackets_to_set_of_sht_packets(sp2@))
            && post2_self_@ == AbstractHostState {
                sd: post2_self_@.sd,
                received_packet: post2_self_@.received_packet,
                ..post2_self_@
            });
}

// Re-anchor each per-run receive_packet on the shared `(pre_v, pkt_v)`
// witnesses so z3's disjunction-elimination sees the two runs sharing a
// scrutinee.
assert(receive_packet(pre_v, post1_self_@, pkt_v,
    abstractify_seq_of_cpackets_to_set_of_sht_packets(sp1@), ack1@@)
    ==> receive_packet(pre_v, post1_self_@, pkt_v,
        abstractify_seq_of_cpackets_to_set_of_sht_packets(sp1@), ack1@@));
assert(receive_packet(pre_v, post2_self_@, pkt_v,
    abstractify_seq_of_cpackets_to_set_of_sht_packets(sp2@), ack2@@)
    ==> receive_packet(pre_v, post2_self_@, pkt_v,
        abstractify_seq_of_cpackets_to_set_of_sht_packets(sp2@), ack2@@));

// Cross-run AbstractHostState skeleton: every field-level equality that
// `host_state_common_postconditions` pins.
assert(post1_self_.host_state_common_postconditions(pre_self_, cpacket, sp1@)
    && post2_self_.host_state_common_postconditions(pre_self_, cpacket, sp2@)
    ==> post1_self_.constants == post2_self_.constants);
assert(post1_self_.host_state_common_postconditions(pre_self_, cpacket, sp1@)
    && post2_self_.host_state_common_postconditions(pre_self_, cpacket, sp2@)
    ==> post1_self_@.constants == post2_self_@.constants);
